import time
from functools import lru_cache
import httpx
from jose import JWTError, jwt as jose_jwt

JWKS_URI   = "https://sso.internal/oauth2/v1/keys"
ISSUER     = "https://sso.internal"
AUDIENCE   = "genai-platform"

@lru_cache(maxsize=1)
def _fetch_jwks(cache_buster: int) -> dict:
    # cache_buster rotates every 5 minutes so the lru_cache refreshes
    resp = httpx.get(JWKS_URI, timeout=5)
    resp.raise_for_status()
    return resp.json()

def get_jwks() -> dict:
    return _fetch_jwks(int(time.time()) // 300)

def validate_token(token: str) -> dict:
    """Return verified claims dict or raise JWTError."""
    header = jose_jwt.get_unverified_header(token)
    jwks   = get_jwks()
    key    = next(
        (k for k in jwks["keys"] if k.get("kid") == header.get("kid")),
        None,
    )
    if key is None:
        # Unknown kid — force a JWKS refresh
        _fetch_jwks.cache_clear()
        jwks = get_jwks()
        key  = next((k for k in jwks["keys"] if k.get("kid") == header["kid"]), None)
    if key is None:
        raise JWTError("No matching signing key")
    return jose_jwt.decode(
        token, key,
        algorithms=["RS256"],
        audience=AUDIENCE,
        issuer=ISSUER,
    )

import logging, json
from opentelemetry import trace as otel_trace

class OTelJSONFormatter(logging.Formatter):
    def format(self, record: logging.LogRecord) -> str:
        ctx  = otel_trace.get_current_span().get_span_context()
        body = {
            "timestamp":  self.formatTime(record, "%Y-%m-%dT%H:%M:%S.%fZ"),
            "level":      record.levelname,
            "logger":     record.name,
            "message":    record.getMessage(),
            "trace_id":   format(ctx.trace_id, "032x") if ctx.is_valid else None,
            "span_id":    format(ctx.span_id,  "016x") if ctx.is_valid else None,
        }
        if record.exc_info:
            body["exception"] = self.formatException(record.exc_info)
        return json.dumps(body)

def configure_logging(level: str = "INFO") -> None:
    handler = logging.StreamHandler()
    handler.setFormatter(OTelJSONFormatter())
    logging.basicConfig(level=level, handlers=[handler], force=True)

import re
from opentelemetry.sdk.trace import SpanProcessor, ReadableSpan

PII_PATTERNS = [
    (re.compile(r"\b\d{3}-\d{2}-\d{4}\b"),             "<SSN>"),
    (re.compile(r"\b4[0-9]{12,15}\b"),                    "<CC>"),
    (re.compile(r"[\w.+-]+@[\w-]+\.[a-z]{2,}",re.I),     "<EMAIL>"),
]
SENSITIVE_ATTRS = {"llm.prompt_text", "llm.completion_text", "rag.query_text"}

class PIIRedactionProcessor(SpanProcessor):
    def on_end(self, span: ReadableSpan) -> None:
        for attr in SENSITIVE_ATTRS:
            val = span.attributes.get(attr)
            if isinstance(val, str):
                for pat, token in PII_PATTERNS:
                    val = pat.sub(token, val)
                # ReadableSpan attrs are frozen; mutation happens via internal dict
                span._attributes[attr] = val  # type: ignore[attr-defined]

    def shutdown(self) -> None: pass
    def force_flush(self, timeout_millis: int = 0) -> bool: return True
